import React from "react";
import EmployeeLayout from "../../components/EmployeeLayout";

function EmployeeCustomDataFieldsPage() {
  return (
    <EmployeeLayout title="Custom Data Fields">
      <div className="table-card">
        <p>No custom data fields available.</p>
      </div>
    </EmployeeLayout>
  );
}

export default EmployeeCustomDataFieldsPage;
